webhooks.request_example:
const octokit = new Octokit({
  auth: 'USER_ACCESS_TOKEN'
});

await octokit.request('POST /repos/{owner}/{repo}/hooks', {
  owner: 'OWNER',
  repo: 'REPO',
  name: 'web',
  active: true,
  events: ['push'],
  config: {
    url: 'https://your-app.example.com/webhooks/github',
    content_type: 'json',
    secret: 'YOUR_WEBHOOK_SECRET',
    insecure_ssl: '0'
  },
  headers: {
    'X-GitHub-Api-Version': '2026-03-10'
  }
});

query.body:
{
  "query": "query recentAcSubmissions($username: String!, $limit: Int!) { recentAcSubmissionList(username: $username, limit: $limit) { id title titleSlug timestamp } }",
  "variables": { "username": "your_username", "limit": 20 }
}

{
  "query": "query userSolvedProblems($username: String!) { allQuestionsCount { difficulty count } matchedUser(username: $username) { submitStatsGlobal { acSubmissionNum { difficulty count } } problemsSolvedBeatsStats { difficulty percentage } } }",
  "variables": { "username": "your_username" }
}

{
  "query": "query submissionList($offset: Int!, $limit: Int!, $lastKey: String) { submissionList(offset: $offset, limit: $limit, lastKey: $lastKey) { lastKey hasNext submissions { id title status timestamp lang question { difficulty } } } }",
  "variables": { "offset": 0, "limit": 20, "lastKey": null }
}
